import './FileUploaderTitle.scss';

import type { FC } from 'react';
import React from 'react';

import { Typography } from '../../Typography';
import type { FileUploaderTitleProps } from './FileUploaderTitle.types';

export const FileUploaderTitle: FC<FileUploaderTitleProps> = ({
	title,
	subTitle,
	dragOver,
	linkName,
	dragOverTitle,
}) => {
	const localTitleVariant = dragOver ? dragOverTitle : title;
	const isComponent = typeof localTitleVariant !== 'string';

	const localTitle = isComponent ? (
		localTitleVariant
	) : (
		<>
			<div className="dsb_file-uploader-title_wrapper">
				<Typography variant="body3" className="dsb_file-uploader-title_text">
					{localTitleVariant}
				</Typography>{' '}
				{linkName && !dragOver && <span className="dsb_file-uploader-title_link">{linkName}</span>}
			</div>

			{subTitle && !dragOver && (
				<Typography variant="body3" className="dsb_file-uploader-title_subtitle">
					{subTitle}
				</Typography>
			)}
		</>
	);

	return (
		<div data-testid="FileUploaderTitle" className="dsb_file-uploader-title">
			{localTitle}
		</div>
	);
};
